// Utilitário de tradução automática gratuita usando Google Translate web API
class AutoTranslator {
  private cache: Map<string, Map<string, string>> = new Map();
  private currentLanguage: string = 'pt';
  private portugueseTexts: Map<string, string> = new Map(); // Armazena textos portugueses originais

  constructor() {
    this.currentLanguage = localStorage.getItem('language') || 'pt';

    // Armazenar textos portugueses originais quando a página carrega
    if (typeof window !== 'undefined') {
      setTimeout(() => {
        console.log('Armazenando textos portugueses originais...');
        this.storePortugueseTexts();
      }, 1500); // Esperar página carregar completamente
    }
  }

  setLanguage(lang: string) {
    this.currentLanguage = lang;
    localStorage.setItem('language', lang);

    console.log(`Definindo idioma para: ${lang}`);

    // Se voltar para português, restaurar texto original
    if (lang === 'pt') {
      console.log('Restaurando texto português original...');
      this.restoreOriginalTexts();
    } else {
      console.log(`Traduzindo para ${lang}...`);
      this.translatePage();
    }
  }

  getCurrentLanguage(): string {
    return this.currentLanguage;
  }

  // Armazenar textos portugueses originais
  storePortugueseTexts() {
    const textNodes = this.getTextNodes(document.body);
    console.log(`Encontrados ${textNodes.length} nós de texto para armazenar`);

    let storedCount = 0;
    for (const node of textNodes) {
      if (node.textContent) {
        const text = node.textContent.trim();
        if (text.length > 0) {
          // Armazenar texto português original
          this.portugueseTexts.set(text, text);
          storedCount++;
        }
      }
    }

    console.log(`Armazenados ${storedCount} textos portugueses originais`);
    console.log(`Total de textos portugueses: ${this.portugueseTexts.size}`);
  }

  // Translate text using Google Translate web API (free)
  async translateText(text: string, fromLang: string = 'pt', toLang: string = 'en'): Promise<string> {
    if (fromLang === toLang) return text;

    // Check cache first
    const cacheKey = `${fromLang}-${toLang}`;
    if (!this.cache.has(cacheKey)) {
      this.cache.set(cacheKey, new Map());
    }
    const langCache = this.cache.get(cacheKey)!;

    if (langCache.has(text)) {
      return langCache.get(text)!;
    }

    try {
      // Use Google Translate web API (free)
      const url = `https://translate.googleapis.com/translate_a/single?client=gtx&sl=${fromLang}&tl=${toLang}&dt=t&q=${encodeURIComponent(text)}`;

      const response = await fetch(url);
      if (!response.ok) {
        throw new Error('Translation API failed');
      }

      const data = await response.json();
      if (data && data[0] && data[0][0] && data[0][0][0]) {
        const translatedText = data[0][0][0];
        langCache.set(text, translatedText);
        return translatedText;
      }
    } catch (error) {
      console.warn('Translation failed, using original text:', error);
    }

    return text; // Fallback to original text
  }

  // Translate all text nodes in the page
  async translatePage() {
    if (this.currentLanguage === 'pt') return; // Skip if Portuguese (original)

    const textNodes = this.getTextNodes(document.body);
    const translations: Promise<void>[] = [];

    for (const node of textNodes) {
      const originalText = node.textContent?.trim();
      if (originalText && originalText.length > 0) {
        translations.push(
          this.translateText(originalText, 'pt', this.currentLanguage)
            .then(translated => {
              if (node.textContent) {
                node.textContent = translated;
              }
            })
        );
      }
    }

    await Promise.all(translations);
  }

  // Get all text nodes from an element
  private getTextNodes(element: Element): Text[] {
    const textNodes: Text[] = [];
    const walker = document.createTreeWalker(
      element,
      NodeFilter.SHOW_TEXT,
      {
        acceptNode: (node) => {
          // Skip script, style, and input elements
          const parent = node.parentElement;
          if (!parent) return NodeFilter.FILTER_REJECT;

          const tagName = parent.tagName.toLowerCase();
          if (['script', 'style', 'noscript', 'input', 'textarea'].includes(tagName)) {
            return NodeFilter.FILTER_REJECT;
          }

          // Skip if text is just whitespace
          if (!node.textContent?.trim()) {
            return NodeFilter.FILTER_REJECT;
          }

          return NodeFilter.FILTER_ACCEPT;
        }
      }
    );

    let node;
    // eslint-disable-next-line no-cond-assign
    while (node = walker.nextNode()) {
      textNodes.push(node as Text);
    }

    return textNodes;
  }

  // Translate a specific element
  async translateElement(element: Element) {
    if (this.currentLanguage === 'pt') return;

    const textNodes = this.getTextNodes(element);
    const translations: Promise<void>[] = [];

    for (const node of textNodes) {
      const originalText = node.textContent?.trim();
      if (originalText && originalText.length > 0) {
        translations.push(
          this.translateText(originalText, 'pt', this.currentLanguage)
            .then(translated => {
              if (node.textContent) {
                node.textContent = translated;
              }
            })
        );
      }
    }

    await Promise.all(translations);
  }

  // Store original text before translation
  public originalTexts: Map<Text, string> = new Map();

  // Store original texts by content for more reliable restoration
  public originalTextsByContent: Map<string, string> = new Map();

  // Store original texts for all elements
  storeOriginalTexts(element: Element = document.body) {
    console.log('Starting storeOriginalTexts...');
    const textNodes = this.getTextNodes(element);
    console.log(`Found ${textNodes.length} text nodes to store`);

    let storedCount = 0;
    for (const node of textNodes) {
      if (node.textContent) {
        const text = node.textContent.trim();
        if (text.length > 0) {
          // Store by node reference
          this.originalTexts.set(node, text);
          // Store by content for reliable restoration
          this.originalTextsByContent.set(text, text);
          storedCount++;
        }
      }
    }

    console.log(`Stored ${storedCount} original Portuguese texts`);
    console.log(`Total stored texts by node: ${this.originalTexts.size}`);
    console.log(`Total stored texts by content: ${this.originalTextsByContent.size}`);
  }

  // Restaurar textos portugueses originais
  restoreOriginalTexts(element: Element = document.body) {
    console.log('Iniciando restauração de textos portugueses...');
    const textNodes = this.getTextNodes(element);
    console.log(`Encontrados ${textNodes.length} nós de texto para restaurar`);
    console.log(`Textos portugueses armazenados: ${this.portugueseTexts.size}`);

    let restoredCount = 0;
    for (const node of textNodes) {
      if (node.textContent) {
        const currentText = node.textContent.trim();
        if (currentText.length > 0) {
          // Procurar texto português correspondente
          const portugueseText = this.portugueseTexts.get(currentText);
          if (portugueseText) {
            if (restoredCount < 3) { // Mostrar primeiros 3 para debug
              console.log(`Restaurando texto: "${currentText}" -> "${portugueseText}"`);
            }
            // Forçar atualização DOM
            node.textContent = portugueseText;
            // Disparar reflow para garantir atualização visual
            const parent = node.parentElement;
            if (parent) {
              parent.style.display = 'none';
              void parent.offsetHeight; // Forçar reflow
              parent.style.display = '';
            }
            restoredCount++;
          }
        }
      }
    }

    console.log(`Restaurados ${restoredCount} textos para português original`);

    // Se nenhum texto foi restaurado, armazenar textos atuais como fallback
    if (restoredCount === 0) {
      console.log('Nenhum texto restaurado, armazenando textos atuais como fallback...');
      this.storePortugueseTexts();
    }
  }
}

// Create global instance
export const autoTranslator = new AutoTranslator();

// Hook for React components
export const useAutoTranslate = () => {
  return {
    translate: (text: string, toLang?: string) => 
      autoTranslator.translateText(text, 'pt', toLang || autoTranslator.getCurrentLanguage()),
    setLanguage: (lang: string) => autoTranslator.setLanguage(lang),
    getCurrentLanguage: () => autoTranslator.getCurrentLanguage(),
    translatePage: () => autoTranslator.translatePage(),
    translateElement: (element: Element) => autoTranslator.translateElement(element)
  };
};
